SELECT tbl1.project_id AS projectId ,tbl1.billing_account_id AS billingAccountId ,tbl1.standard_cost AS latestCost ,COALESCE(tbl2.avg_cost, 0) AS avgCost ,COALESCE(tbl1.service_cd, tbl1.project_id) AS projectCd ,(SELECT sm.workspace_cd FROM servicegroup_meta sm WHERE sm.csp_type = 'GCP' AND sm.service_cd COLLATE utf8mb4_uca1400_ai_ci = tbl1.service_cd LIMIT 1) AS workspaceCd FROM ( SELECT project_id ,billing_account_id ,service_cd ,SUM(cost) AS standard_cost FROM gcp_billing_raw WHERE DATE(usage_start_time) = #{standardDT} GROUP BY project_id, billing_account_id, service_cd ) tbl1 LEFT JOIN ( SELECT project_id ,service_cd ,AVG(daily_cost) AS avg_cost FROM ( SELECT project_id ,service_cd ,DATE(usage_start_time) AS usage_date ,SUM(cost) AS daily_cost FROM gcp_billing_raw WHERE DATE(usage_start_time) IN (
#{item}
) GROUP BY project_id, service_cd, DATE(usage_start_time) ) daily GROUP BY project_id, service_cd ) tbl2 ON tbl2.project_id = tbl1.project_id AND tbl2.service_cd <=> tbl1.service_cd

mapper.insert:
INSERT INTO daily_abnormal_by_product (
     collect_dt
    ,product_cd
    ,abnormal_rating
    ,percentage_point
    ,standard_cost
    ,subject_cost
    ,project_cd
    ,workspace_cd
    ,csp_type
) VALUES (
     #{collectDt}
    ,#{productCd}
    ,#{abnormalRating}
    ,#{percentagePoint}
    ,#{standardCost}
    ,#{subjectCost}
    ,#{projectCd}
    ,#{workspaceCd}
    ,#{cspType}
)
ON DUPLICATE KEY UPDATE
     abnormal_rating  = VALUES(abnormal_rating)
    ,percentage_point = VALUES(percentage_point)
    ,standard_cost    = VALUES(standard_cost)
    ,subject_cost     = VALUES(subject_cost)

INSERT INTO gcp_billing_raw (
     created
    ,billing_account_id
    ,cost
    ,cost_type
    ,currency
    ,currency_conversion_rate
    ,export_time
    ,invoice_month
    ,service_id
    ,service_description
    ,sku_id
    ,sku_description
    ,project_id
    ,project_number
    ,project_name
    ,project_ancestry_numbers
    ,location
    ,location_country
    ,location_region
    ,location_zone
    ,usage_start_time
    ,usage_end_time
    ,usage_amount
    ,usage_unit
    ,usage_amount_in_pricing_units
    ,usage_pricing_unit
    ,adjustment_info_id
    ,adjustment_info_description
    ,adjustment_info_mode
    ,adjustment_info_type
    ,labels
    ,system_labels
    ,tags
    ,csp_instanceid
    ,vm_id
    ,mci_id
    ,service_cd
) VALUES

(
     NOW()
    ,#{item.billingAccountId}
    ,#{item.cost}
    ,#{item.costType}
    ,#{item.currency}
    ,#{item.currencyConversionRate}
    ,#{item.exportTime}
    ,#{item.invoiceMonth}
    ,#{item.serviceId}
    ,#{item.serviceDescription}
    ,#{item.skuId}
    ,#{item.skuDescription}
    ,#{item.projectId}
    ,#{item.projectNumber}
    ,#{item.projectName}
    ,#{item.projectAncestryNumbers}
    ,#{item.location}
    ,#{item.locationCountry}
    ,#{item.locationRegion}
    ,#{item.locationZone}
    ,#{item.usageStartTime}
    ,#{item.usageEndTime}
    ,#{item.usageAmount}
    ,#{item.usageUnit}
    ,#{item.usageAmountInPricingUnits}
    ,#{item.usagePricingUnit}
    ,#{item.adjustmentInfoId}
    ,#{item.adjustmentInfoDescription}
    ,#{item.adjustmentInfoMode}
    ,#{item.adjustmentInfoType}
    ,#{item.labels}
    ,#{item.systemLabels}
    ,#{item.tags}
    ,#{item.cspInstanceid}
    ,#{item.vmId}
    ,#{item.mciId}
    ,#{item.serviceCd}
)
